parameters.jsCode:
const body = $input.first().json.body;

const fromAddress = body.fromAddress || 'New York, NY';
const toAddress = body.toAddress || 'Los Angeles, CA';
const weight = Math.min(parseFloat(body.weight) || 5, 70); // UPS 上限 70lb
const dimensions = body.dimensions || { length: '10', width: '10', height: '10' };

// 预设真实美国地址，按城市名匹配（Demo 用，保证 Shippo 能返回费率）
const ADDRESS_MAP = {
  'new york':    { street1: '1 World Trade Center', city: 'New York',      state: 'NY', zip: '10007' },
  'ny':          { street1: '1 World Trade Center', city: 'New York',      state: 'NY', zip: '10007' },
  'los angeles': { street1: '200 N Spring St',      city: 'Los Angeles',   state: 'CA', zip: '90012' },
  'la':          { street1: '200 N Spring St',      city: 'Los Angeles',   state: 'CA', zip: '90012' },
  'chicago':     { street1: '121 N LaSalle St',     city: 'Chicago',       state: 'IL', zip: '60602' },
  'houston':     { street1: '901 Bagby St',         city: 'Houston',       state: 'TX', zip: '77002' },
  'phoenix':     { street1: '200 W Washington St',  city: 'Phoenix',       state: 'AZ', zip: '85003' },
  'san francisco': { street1: '1 Dr Carlton B Goodlett Pl', city: 'San Francisco', state: 'CA', zip: '94102' },
  'sf':          { street1: '1 Dr Carlton B Goodlett Pl', city: 'San Francisco', state: 'CA', zip: '94102' },
  'seattle':     { street1: '600 4th Ave',          city: 'Seattle',       state: 'WA', zip: '98104' },
  'miami':       { street1: '400 NW 2nd Ave',       city: 'Miami',         state: 'FL', zip: '33128' },
  'dallas':      { street1: '1500 Marilla St',      city: 'Dallas',        state: 'TX', zip: '75201' },
  'boston':      { street1: '1 City Hall Square',   city: 'Boston',        state: 'MA', zip: '02201' },
};

function resolveAddress(input) {
  const key = input.toLowerCase().replace(/,.*$/, '').trim();
  return ADDRESS_MAP[key] || ADDRESS_MAP['new york']; // 默认纽约
}

const from = resolveAddress(fromAddress);
const to = resolveAddress(toAddress);

return {
  shippoPayload: {
    address_from: { name: 'CargoFlow Sender', ...from, country: 'US' },
    address_to:   { name: 'CargoFlow Recipient', ...to, country: 'US' },
    parcels: [{
      length: String(dimensions.length || '10'),
      width:  String(dimensions.width  || '10'),
      height: String(dimensions.height || '10'),
      distance_unit: 'in',
      weight: String(weight),
      mass_unit: 'lb'
    }],
    async: false
  },
  fromAddress,
  toAddress,
  weight
};

// 解析 Shippo 返回的 shipment 和 rates
const shippo = $input.first().json;
const prev = $input.first().json;

// 取上一节点的原始入参（通过节点引用）
const fromAddress = $('Prepare Shippo Request').first().json.fromAddress;
const toAddress = $('Prepare Shippo Request').first().json.toAddress;
const weight = $('Prepare Shippo Request').first().json.weight;

if (!shippo.object_id) {
  throw new Error('Shippo API 返回异常: ' + JSON.stringify(shippo));
}

// rates 按价格排序，取最优
const rates = (shippo.rates || []).sort((a, b) => parseFloat(a.amount) - parseFloat(b.amount));
const bestRate = rates[0];

if (!bestRate) {
  throw new Error('Shippo 未返回任何费率，请检查地址是否有效');
}

const quoteAmount = parseFloat(bestRate.amount);

return {
  fromAddress,
  toAddress,
  weight,
  quoteAmount,
  shippoObjectId: shippo.object_id,
  shippoRateId: bestRate.object_id,
  carrier: bestRate.provider,
  serviceName: bestRate.servicelevel?.name || bestRate.servicelevel_name || '',
  estimatedDays: bestRate.estimated_days,
  allRates: rates.slice(0, 5).map(r => ({
    rateId: r.object_id,
    carrier: r.provider,
    service: r.servicelevel?.name || '',
    amount: parseFloat(r.amount),
    currency: r.currency,
    estimatedDays: r.estimated_days
  })),
  status: 'draft'
};

